class Account:
    def __init__(self, balance):
        self.balance = balance

    def balance(self):
        return 150

    def deposit(self, amount):
        self.balance += amount
        return self.balance

    def withdraw(self, amount):
        if amount <= self.balance:
            self.balance -= amount
        return self.balance

